const wf = $input.first().json;

// Calcular fecha objetivo desde fecha_referencia (nunca del LLM)
const texto = String(wf.fecha_texto || 'hoy').toLowerCase().trim();
const ref = DateTime.fromISO(wf.fecha_referencia || DateTime.now().toISO()).setZone('America/Guayaquil');

let target;
if (texto === 'ayer') {
  target = ref.minus({ days: 1 }).startOf('day');
} else if (texto === 'hoy') {
  target = ref.startOf('day');
} else if (texto === 'mañana') {
  target = ref.plus({ days: 1 }).startOf('day');
} else if (texto === 'pasado mañana') {
  target = ref.plus({ days: 2 }).startOf('day');
} else {
  // Intentar parsear como ISO o fecha parcial
  const parsed = DateTime.fromISO(texto).setZone('America/Guayaquil');
  if (parsed.isValid) {
    // Si el año es más de 2 años antes del actual, asumir que el LLM alucinó y usar mañana
    if (ref.year - parsed.year >= 2) {
      target = ref.plus({ days: 1 }).startOf('day');
    } else {
      target = parsed.startOf('day');
    }
  } else {
    // Fallback: hoy
    target = ref.startOf('day');
  }
}

const diaInicio = target.toISO();
const diaFin = target.endOf('day').toISO();
const tipoFiltro = String(wf.tipo_evento || 'todos').toLowerCase();
const asesorPhone = String(wf.telefono_asesor || '').trim();

return [{ json: { dia_inicio: diaInicio, dia_fin: diaFin, tipo_filtro: tipoFiltro, asesor_phone: asesorPhone } }];

const items = $input.all();
const calc = $('Calcular Fecha Objetivo').first().json;

const diaInicio = new Date(calc.dia_inicio);
const diaFin    = new Date(calc.dia_fin);
const tipoFiltro   = String(calc.tipo_filtro || 'todos').toLowerCase();
const asesorPhone  = (calc.asesor_phone || '').trim();

const eventos = [];

for (const item of items) {
  const ev  = item.json;
  const summary = (ev.summary || '').toLowerCase();
  const desc    = ev.description || '';

  // Skip internal block events
  if (summary.startsWith('[bloqueo]') || desc.includes('[BLOQUEO_CITAS]')) continue;

  const startRaw = ev.start?.dateTime || ev.start?.date;
  if (!startRaw) continue;

  const startDate = new Date(startRaw);
  if (startDate < diaInicio || startDate > diaFin) continue;

  // Filter by asesor phone ([tel_asesor:...] tag)
  if (asesorPhone) {
    const m = desc.match(/\[tel_asesor:([^\]]+)\]/);
    const phone = m ? m[1].trim() : null;
    if (phone && phone !== asesorPhone) continue;
  }

  // Extract event type
  let tipo = 'Evento';
  const mTipo = desc.match(/\[tipo:([^\]]+)\]/i);
  if (mTipo) tipo = mTipo[1].trim();
  const tipoLower = tipo.toLowerCase();
  if (tipoFiltro !== 'todos' && tipoLower !== tipoFiltro) continue;

  const horaFormato = ev.start?.dateTime
    ? new Date(ev.start.dateTime).toLocaleTimeString('es-EC', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Guayaquil' })
    : 'Todo el día';

  const fechaFormato = new Date(startRaw).toLocaleDateString('es-EC', {
    weekday: 'long', day: '2-digit', month: 'long', year: 'numeric', timeZone: 'America/Guayaquil'
  });

  eventos.push({
    hora: horaFormato,
    fecha: fechaFormato,
    tipo,
    titulo: ev.summary || 'Sin título',
    event_id: ev.id || ''  // ← include Google Calendar event ID
  });
}

if (eventos.length === 0) {
  const etiqueta  = tipoFiltro === 'todos' ? 'eventos' : `eventos de tipo "${tipoFiltro}"`;
  const fechaTexto = diaInicio.toLocaleDateString('es-EC', {
    weekday: 'long', day: '2-digit', month: 'long', year: 'numeric', timeZone: 'America/Guayaquil'
  });
  return [{ json: { resultado: `Para el ${fechaTexto} no tienes ${etiqueta} registrados en tu calendario.` } }];
}

eventos.sort((a, b) => a.hora.localeCompare(b.hora));

const etiqueta   = tipoFiltro === 'todos' ? 'eventos' : `eventos de tipo "${tipoFiltro}"`;
const fechaTexto = diaInicio.toLocaleDateString('es-EC', {
  weekday: 'long', day: '2-digit', month: 'long', year: 'numeric', timeZone: 'America/Guayaquil'
});

let texto = `Estos son tus ${etiqueta} para el ${fechaTexto}:\n\n`;
for (const ev of eventos) {
  // Include event_id as hidden tag for the agent — NOT shown to user in the final response
  texto += `- ${ev.hora} - ${ev.tipo}: ${ev.titulo} [event_id:${ev.event_id}]\n`;
}

return [{ json: { resultado: texto.trim() } }];
